package travelcare_agent.evaluation.dto; import travelcare_agent.evaluation.entity.EvaluationCase; public record EvaluationCaseResponse(Long id,Long datasetId,String caseKey,String name,Long sourceTraceId,String expectationJson,String tagsJson,Boolean enabled){public static EvaluationCaseResponse from(EvaluationCase v){return new EvaluationCaseResponse(v.getId(),v.getDatasetId(),v.getCaseKey(),v.getName(),v.getSourceTraceId(),v.getExpectationJson(),v.getTagsJson(),v.getEnabled());}}
